import assertk.assertFailure
import assertk.assertThat
import assertk.assertions.containsExactly
import assertk.assertions.isEmpty
import assertk.assertions.isInstanceOf
import com.fsck.k9.mail.Address
import kotlin.test.Test

/**
 * Tests for validation of invalid email addresses in UserInputEmailAddressParser.
 * These tests specifically verify the fix for the issue where email addresses
 * with invalid hostnames (e.g., containing '/') were not being properly validated.
 */
class UserInputEmailAddressParserInvalidAddressTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `email address with trailing slash should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user@gmail.com/")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `email address with slash in hostname should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user@domain.com/path")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `email address with underscore in hostname should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user@domain_test.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `valid email address should be parsed correctly`() {
        val addresses = parser.parse("user@domain.example")
        assertThat(addresses).containsExactly(Address("user@domain.example"))
    }

    @Test
    fun `email address with hyphen in hostname should be parsed correctly`() {
        val addresses = parser.parse("user@my-domain.com")
        assertThat(addresses).containsExactly(Address("user@my-domain.com"))
    }

    @Test
    fun `email address with numbers in hostname should be parsed correctly`() {
        val addresses = parser.parse("user@domain123.com")
        assertThat(addresses).containsExactly(Address("user@domain123.com"))
    }

    @Test
    fun `email address with multiple subdomains should be parsed correctly`() {
        val addresses = parser.parse("user@sub.domain.example.org")
        assertThat(addresses).containsExactly(Address("user@sub.domain.example.org"))
    }

    @Test
    fun `email address with single character labels should be parsed correctly`() {
        val addresses = parser.parse("user@a.b.c")
        assertThat(addresses).containsExactly(Address("user@a.b.c"))
    }
}
